args.sparql:
SELECT ?disestablishment WHERE {
  wd:Q1374030 wdt:P131 ?parkLocation .
  ?ride wdt:P31 wd:Q2252508 ;
         rdfs:label "Log Flume"@en ;
         wdt:P276 wd:Q1374030 ;
         wdt:P576 ?disestablishment .
}

SELECT ?disestablishment WHERE {
  wd:Q1374030 wdt:P31 wd:Q40223 ;
         wdt:P131 ?parkLocation .
  ?ride wdt:P31 wd:Q2252508 ;
         rdfs:label ?label ;
         wdt:P276 wd:Q1374030 ;
         wdt:P576 ?disestablishment .
  FILTER (LANG(?label) = 'en')
  FILTER (regex(?label, 'log flume', 'i'))
}

